using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: EF9 renamed the discriminator JSON property
        // from "Discriminator" to "$type". Existing documents use "Discriminator",
        // so explicitly keep the old name.
        modelBuilder.Entity<Blog>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Blog>("Blog");

        // Breaking change #2: EF9 no longer prepends "{Discriminator}|" to
        // generated id values. Existing documents use "Blog|1" format, so
        // restore that pattern with a custom value generator.
        modelBuilder.Entity<Blog>()
            .Property(b => b.Id)
            .HasValueGenerator<LegacyIdValueGenerator>();

        // Breaking change #3: HasIndex() now throws on the Cosmos provider.
        // Cosmos manages indexing via its own indexing policy — remove the call.
        // (was: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);)
    }
}

/// <summary>
/// Restores the pre-9.0 id format: "{Discriminator}|{Guid}".
/// </summary>
class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
            ?? entry.Metadata.ShortName();
        return $"{discriminator}|{Guid.NewGuid()}";
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

